style.css:
@import url("https://fonts.googleapis.com/css2?family=Cherry+Bomb+One&display=swap");
* {
  box-sizing: border-box;
}

body {
  min-height: 100vh;
  color: #222;
  background-color: #ececec;
  font-family: "Cherry Bomb One", system-ui;
  display: flex;
  justify-content: center;
  align-items: center;
}

.wrapper {
  position: relative;
  transform-style: preserve-3d;
}

.title {
  font-size: 100px;
  color: #ffcc33;
  text-stroke: 3px #fff;
  paint-order: stroke fill;
  filter: drop-shadow(5px 5px 0px orange);
  letter-spacing: 3px;
  white-space: nowrap;
  text-box: trim-start cap alphabetic;
}
@media (max-width: 768px) {
  .title {
    font-size: 50px;
  }
}

.ring {
  --width: 100px;
  --img-translate-x: 120%;
  position: absolute;
  inset: 0;
  margin: auto;
  width: var(--width);
  aspect-ratio: 16/9;
  transform-style: preserve-3d;
  perspective: 1200px;
  transform: rotateX(-20deg) rotateZ(30deg) rotateY(var(--spin));
  animation: spin 45s linear both infinite;
  --slide-deg: calc(360deg / var(--total));
}
.ring img {
  position: absolute;
  width: 100%;
  height: 100%;
  object-fit: cover;
  border-radius: 12px;
  transform: rotateY(calc(var(--i) * var(--slide-deg))) translateX(var(--img-translate-x)) rotateY(90deg);
}
@media (max-width: 768px) {
  .ring {
    --width: 70px;
    --img-translate-x: 110%;
  }
}

@property --spin {
  syntax: "<angle>";
  inherits: false;
  initial-value: 0deg;
}
@keyframes spin {
  to {
    --spin: 360deg;
  }
}
